if accion.find(':') >= 0:
	accion, arg = lista(accion, ':', 2)

if accion == 'a_pone_ventas':
	cdvd = arg
	albs = []
	cdalbs = selec(gpx, 'alb-venta', '0', [['AV_VD', '=', cdvd]], 'AV_FEC')
	for cdalb in cdalbs:
		alb = lee(cl, gpx, 'alb-venta', cdalb)
		if alb == 1:
			continue
		cdcli = alb<AV_CCL>
		cli = lee(cl, gpx, 'clientes', cdcli)
		if cli == 1:
			continue
		albs.append(['A' + cdalb, alb<AV_TIP>, alb<AV_FEC>, cdcli, cli<CL_DENO>, alb<AV_TTT>])

	cdalbs = selec(gpx, 'alb-oventa', '0', [['OV_VD', '=', cdvd]], 'OV_FEC')
	for cdalb in cdalbs:
		alb = lee(cl, gpx, 'alb-oventa', cdalb)
		if alb == 1:
			continue
		cdcli = alb<OV_CCL>
		cli = lee(cl, gpx, 'clientes', cdcli)
		if cli == 1:
			continue
		albs.append(['P' + cdalb, alb<OV_TIP>, alb<OV_FEC>, cdcli, cli<CL_DENO>, alb<OV_TTT>])

	peds = []
	cdpeds = selec(gpx, 'pedidos_cl', '0', [['PD_VD', '=', cdvd]], 'PD_FEC')
	for cdped in cdpeds:
		ped = lee(cl, gpx, 'pedidos_cl', cdped)
		if ped == 1:
			continue
		cdcli = ped<PD_CCL>
		cli = lee(cl, gpx, 'clientes', cdcli)
		if cli == 1:
			continue
		peds.append([cdped, ped<PD_FEC>, cdcli, cli<CL_DENO>, ped<PD_TTT>])

	self.envia(cl, (albs, peds))

elif accion == 'a_pon_detalle':
	cod, tipo = arg
	resul = []
	if tipo == '0':
		tipo, cod = cod[0], cod[1:] # El código es: A000001 ó P000002
		if tipo == 'A':
			alb = lee(cl, gpx, 'alb-venta', cod)
			if alb != 1:
				lnas = alb<AV_LNA>
		elif tipo == 'P':
			alb = lee(cl, gpx, 'alb-oventa', cod)
			if alb != 1:
				lnas = alb<OV_LNA>
		if alb != 1:
			for lna in lnas:
				cdar, cajas, uds, pvp, dtod, dto, lote = lna[:7]
				ar = lee(cl, gpx, 'articulos', cdar)
				if ar == 1:
					continue
				neto = (pvp - dtod) - ((pvp - dtod) * dto / 100)
				impo = uds * neto
				resul.append([cdar, ar<AR_DENO>, uds, pvp, dtod, dto, neto, impo])
	else:
		ped = lee(cl, gpx, 'pedidos_cl', cod)
		if ped != 1:
			for lna in ped<PD_LNA>:
				cdar, cajas, uds, pvp, dtod, dto, udsv, pcoste, lote = lna[:9]
				ar = lee(cl, gpx, 'articulos', cdar)
				if ar == 1:
					continue
				neto = (pvp - dtod) - ((pvp - dtod) * dto / 100)
				impo = uds * neto
				resul.append([cdar, ar<AR_DENO>, uds, pvp, dtod, dto, neto, impo])

	self.envia(cl, resul)
